#!/usr/bin/env bash
set -uo pipefail

# Generated by analysis/phase2_preflight.py.
# FINAL jobs only. Jobs continue independently after a failure.
DEVICE="${DEVICE:-cuda:0}"
failures=0

run_job() {
  local log="$1"
  shift
  mkdir -p "$(dirname "$log")"
  if ! "$@" >"$log" 2>&1; then
    printf "FAILED: %s (see %s)\n" "$*" "$log" >&2
    failures=$((failures + 1))
  fi
}

